module float_multi(
    input clk,
    input rst,
    input [31:0] a,
    input [31:0] b,
    output reg [31:0] z
);

reg [2:0] counter;
reg [23:0] a_mantissa, b_mantissa, z_mantissa;
reg [9:0] a_exponent, b_exponent, z_exponent;
reg a_sign, b_sign, z_sign;
reg [49:0] product;
reg guard_bit, round_bit, sticky;

reg a_is_zero, b_is_zero;
reg a_is_inf, b_is_inf;
reg a_is_nan, b_is_nan;

reg [22:0] frac_out;
reg [9:0] exp_sum;
reg [9:0] exp_adj;
reg [49:0] product_norm;
reg special_valid;
reg [31:0] special_result;
reg round_up;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        counter       <= 3'd0;
        z             <= 32'd0;
        a_mantissa    <= 24'd0;
        b_mantissa    <= 24'd0;
        z_mantissa    <= 24'd0;
        a_exponent    <= 10'd0;
        b_exponent    <= 10'd0;
        z_exponent    <= 10'd0;
        a_sign        <= 1'b0;
        b_sign        <= 1'b0;
        z_sign        <= 1'b0;
        product       <= 50'd0;
        guard_bit     <= 1'b0;
        round_bit     <= 1'b0;
        sticky        <= 1'b0;
        a_is_zero     <= 1'b0;
        b_is_zero     <= 1'b0;
        a_is_inf      <= 1'b0;
        b_is_inf      <= 1'b0;
        a_is_nan      <= 1'b0;
        b_is_nan      <= 1'b0;
        frac_out      <= 23'd0;
        exp_sum       <= 10'd0;
        exp_adj       <= 10'd0;
        product_norm  <= 50'd0;
        special_valid <= 1'b0;
        special_result<= 32'd0;
        round_up      <= 1'b0;
    end else begin
        case (counter)
            3'd0: begin
                a_sign <= a[31];
                b_sign <= b[31];
                z_sign <= a[31] ^ b[31];

                a_exponent <= (a[30:23] == 8'd0) ? 10'd1 : {2'b00, a[30:23]};
                b_exponent <= (b[30:23] == 8'd0) ? 10'd1 : {2'b00, b[30:23]};

                a_mantissa <= (a[30:23] == 8'd0) ? {1'b0, a[22:0]} : {1'b1, a[22:0]};
                b_mantissa <= (b[30:23] == 8'd0) ? {1'b0, b[22:0]} : {1'b1, b[22:0]};

                a_is_zero <= (a[30:23] == 8'd0) && (a[22:0] == 23'd0);
                b_is_zero <= (b[30:23] == 8'd0) && (b[22:0] == 23'd0);

                a_is_inf <= (a[30:23] == 8'hFF) && (a[22:0] == 23'd0);
                b_is_inf <= (b[30:23] == 8'hFF) && (b[22:0] == 23'd0);

                a_is_nan <= (a[30:23] == 8'hFF) && (a[22:0] != 23'd0);
                b_is_nan <= (b[30:23] == 8'hFF) && (b[22:0] != 23'd0);

                special_valid  <= 1'b0;
                special_result <= 32'd0;

                counter <= 3'd1;
            end

            3'd1: begin
                if (a_is_nan || b_is_nan) begin
                    special_valid  <= 1'b1;
                    special_result <= 32'h7FC00000;
                end else if ((a_is_inf && b_is_zero) || (b_is_inf && a_is_zero)) begin
                    special_valid  <= 1'b1;
                    special_result <= 32'h7FC00000;
                end else if (a_is_inf || b_is_inf) begin
                    special_valid  <= 1'b1;
                    special_result <= {z_sign, 8'hFF, 23'd0};
                end else if (a_is_zero || b_is_zero) begin
                    special_valid  <= 1'b1;
                    special_result <= {z_sign, 8'd0, 23'd0};
                end else begin
                    special_valid  <= 1'b0;
                    exp_sum        <= a_exponent + b_exponent - 10'd127;
                    product        <= a_mantissa * b_mantissa;
                end
                counter <= 3'd2;
            end

            3'd2: begin
                if (special_valid) begin
                    z <= special_result;
                    counter <= 3'd0;
                end else begin
                    if (product[47]) begin
                        product_norm <= {2'b00, product[47:0]};
                        exp_adj      <= exp_sum;
                    end else begin
                        product_norm <= ({2'b00, product[47:0]} << 1);
                        exp_adj      <= exp_sum - 10'd1;
                    end
                    counter <= 3'd3;
                end
            end

            3'd3: begin
                z_exponent <= exp_adj;
                z_mantissa <= product_norm[47:24];

                guard_bit <= product_norm[23];
                round_bit <= product_norm[22];
                sticky    <= |product_norm[21:0];

                frac_out  <= product_norm[46:24];
                round_up  <= product_norm[23] && (product_norm[22] || (|product_norm[21:0]) || product_norm[24]);

                counter <= 3'd4;
            end

            3'd4: begin
                if (round_up) begin
                    z_mantissa <= z_mantissa + 24'd1;
                end

                if (round_up && (z_mantissa == 24'hFFFFFF)) begin
                    z_exponent <= z_exponent + 10'd1;
                    z_mantissa <= 24'h800000;
                end

                counter <= 3'd5;
            end

            3'd5: begin
                if (z_exponent >= 10'd255) begin
                    z <= {z_sign, 8'hFF, 23'd0};
                end else if (z_exponent <= 10'd0) begin
                    z <= {z_sign, 8'd0, 23'd0};
                end else begin
                    z <= {z_sign, z_exponent[7:0], z_mantissa[22:0]};
                end
                counter <= 3'd0;
            end

            default: begin
                counter <= 3'd0;
            end
        endcase
    end
end

endmodule

