                if (!(result_is_nan || result_is_inf || result_is_zero)) begin
                    mant_a_mult <= a_mantissa;
                    mant_b_mult <= b_mantissa;
                    product <= a_mantissa * b_mantissa;
                    z_exponent <= a_exponent + b_exponent - 10'd127;
                end
                counter <= 3'd3;
