module traffic_light(
    input  wire       rst_n,
    input  wire       clk,
    input  wire       pass_request,
    output wire [7:0] clock,
    output reg        red,
    output reg        yellow,
    output reg        green
);

parameter idle      = 2'b00;
parameter s1_red    = 2'b01;
parameter s2_yellow = 2'b10;
parameter s3_green  = 2'b11;

reg [7:0] cnt;
reg [1:0] state;
reg       p_red, p_yellow, p_green;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state    <= idle;
        p_red    <= 1'b0;
        p_yellow <= 1'b0;
        p_green  <= 1'b0;
    end else begin
        case (state)
            idle: begin
                p_red    <= 1'b0;
                p_yellow <= 1'b0;
                p_green  <= 1'b0;
                state    <= s1_red;
            end

            s1_red: begin
                p_red    <= 1'b1;
                p_yellow <= 1'b0;
                p_green  <= 1'b0;
                if (cnt == 8'd1)
                    state <= s3_green;
                else
                    state <= s1_red;
            end

            s2_yellow: begin
                p_red    <= 1'b0;
                p_yellow <= 1'b1;
                p_green  <= 1'b0;
                if (cnt == 8'd1)
                    state <= s1_red;
                else
                    state <= s2_yellow;
            end

            s3_green: begin
                p_red    <= 1'b0;
                p_yellow <= 1'b0;
                p_green  <= 1'b1;
                if (cnt == 8'd1)
                    state <= s2_yellow;
                else
                    state <= s3_green;
            end

            default: begin
                p_red    <= 1'b0;
                p_yellow <= 1'b0;
                p_green  <= 1'b0;
                state    <= idle;
            end
        endcase
    end
end

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        cnt <= 8'd10;
    end else if (pass_request && green && (cnt > 8'd10)) begin
        cnt <= 8'd10;
    end else if (!green && p_green) begin
        cnt <= 8'd5;
    end else if (!yellow && p_yellow) begin
        cnt <= 8'd10;
    end else if (!red && p_red) begin
        cnt <= 8'd60;
    end else if (state == idle) begin
        cnt <= 8'd10;
    end else if (cnt != 8'd0) begin
        cnt <= cnt - 8'd1;
    end else begin
        cnt <= cnt;
    end
end

assign clock = cnt;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        red    <= 1'b0;
        yellow <= 1'b0;
        green  <= 1'b0;
    end else begin
        red    <= p_red;
        yellow <= p_yellow;
        green  <= p_green;
    end
end

endmodule

